import{_ as o,o as r,c as t,a0 as l}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"🛠️ 管理員與維護指南","description":"","frontmatter":{},"headers":[],"relativePath":"Admin-Manual.md","filePath":"Admin-Manual.md"}'),a={name:"Admin-Manual.md"};function n(i,e,s,d,c,g){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="🛠️-管理員與維護指南" tabindex="-1">🛠️ 管理員與維護指南 <a class="header-anchor" href="#🛠️-管理員與維護指南" aria-label="Permalink to &quot;🛠️ 管理員與維護指南&quot;">​</a></h1><p>本章節介紹擁有管理員權限的使用者或控制台，如何調控伺服器經濟、建立系統無限商店，以及對違規商店進行強制維護與清理。</p><hr><h2 id="_1-⚙️-管理員經濟調控指令" tabindex="-1">1. ⚙️ 管理員經濟調控指令 <a class="header-anchor" href="#_1-⚙️-管理員經濟調控指令" aria-label="Permalink to &quot;1. ⚙️ 管理員經濟調控指令&quot;">​</a></h2><p>管理員可以手動調整玩家的帳戶金幣：</p><ul><li><strong>發放金幣給玩家</strong>： <code>/addmoney &lt;玩家ID&gt; &lt;金幣金額&gt;</code><ul><li><em>範例</em>：<code>/addmoney Yanggu 5000</code></li><li><em>效果</em>：為指定玩家的虛擬帳戶增加 5000 金幣。</li></ul></li><li><strong>扣除玩家金幣</strong>： <code>/removemoney &lt;玩家ID&gt; &lt;金幣金額&gt;</code><ul><li><em>範例</em>：<code>/removemoney Yanggu 1000</code></li><li><em>效果</em>：扣除指定玩家虛擬帳戶內的 1000 金幣。</li></ul></li></ul><hr><h2 id="_2-🏛️-建立「系統無限商店」-server-shop" tabindex="-1">2. 🏛️ 建立「系統無限商店」（Server Shop） <a class="header-anchor" href="#_2-🏛️-建立「系統無限商店」-server-shop" aria-label="Permalink to &quot;2. 🏛️ 建立「系統無限商店」（Server Shop）&quot;">​</a></h2><p>管理員可建立無限買賣的系統商店：</p><ol><li>依照一般流程建立商店（手持物品左鍵點擊箱子並完成定價）。</li><li>身為管理員，您可以使用右鍵點擊該商店的告示牌，開啟管理面板。</li><li>點選 <strong>「無限模式：停用」</strong> 旁邊的 <strong><code>[修改]</code></strong> 按鈕，將其切換為 <strong><code>啟用</code></strong>。</li><li><strong>系統商店的行為</strong>： <ul><li>該商店的商品庫存會變為 <strong>無限</strong>，買家可無限量購買。</li><li>該商店的收購金幣會變為 <strong>無限</strong>，玩家可無限量賣入以換取金幣。</li><li>玩家向系統商店購買商品所支付的金幣會被系統<strong>直接銷毀</strong>，移出市場流通；玩家賣出商品給系統商店獲得的金幣則由系統直接發放。</li><li>管理員可使用管理面板中的 <code>[遠端補貨]</code> 與 <code>[清空商品]</code> 功能來一鍵填滿或排空箱子。</li></ul></li></ol><hr><h2 id="🚨-3-違規商店的強制清理與維護" tabindex="-1">🚨 3. 違規商店的強制清理與維護 <a class="header-anchor" href="#🚨-3-違規商店的強制清理與維護" aria-label="Permalink to &quot;🚨 3. 違規商店的強制清理與維護&quot;">​</a></h2><p>當發現玩家將商店放置於違規區域時，管理員可以進行強制清理：</p><ul><li><strong>物理強制破壞</strong>：管理員可直接在創造模式下破壞商店箱子或告示牌。系統會立即捕捉此事件，並在系統記錄中安全註銷該商店，同時<strong>清除</strong>箱子正上方的懸浮物品模型，防止殘留。</li><li><strong>遠端強制註銷</strong>：管理員在 <strong>/shop</strong> 選單中點選任何玩家名下的商店時，選單中除了傳送按鈕外，會多出一個紅色的 <strong><code>[ 強制註銷商店 ]</code></strong> 按鈕，點擊即可完成遠端清除。</li></ul>',14)])])}const u=o(a,[["render",n]]);export{h as __pageData,u as default};
